module binary_counter(
    input                 clk,
    input                 rst,
    input                 en,
    output  reg [2:0]     count
);

// Counter logic
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst) begin
        count <= 3'd0;
    end else if (en) begin
        count <= count + 1;
    end
end

endmodule
